import{_ as i,c as h,a1 as t,o as c}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Social Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md","filePath":"vi/categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md"}'),a={name:"vi/categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md"};function g(e,n,o,r,s,l){return c(),h("div",null,n[0]||(n[0]=[t('<h1 id="social-engineering" tabindex="-1">Social Engineering <a class="header-anchor" href="#social-engineering" aria-label="Permalink to &quot;Social Engineering&quot;">​</a></h1><p>Social engineering (Kỹ thuật xã hội) là nghệ thuật thao túng con người để họ cung cấp thông tin bảo mật. Loại thông tin mà những kẻ tấn công tìm kiếm có thể khác nhau, nhưng khi một cá nhân bị nhắm mục tiêu, chúng thường cố gắng lừa bạn cung cấp mật khẩu hoặc thông tin ngân hàng, hoặc truy cập vào máy tính của bạn để cài đặt phần mềm độc hại – cho phép chúng truy cập mật khẩu và thông tin ngân hàng của bạn cũng như kiểm soát máy tính của bạn.</p><p><a href="https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539" target="_blank" rel="noreferrer">Báo cáo trắng của McAfee &quot;Hacking the Human Operating System&quot;</a> tập trung vào việc sử dụng kỹ thuật xã hội để tấn công người dùng gia đình và doanh nghiệp, và một lần nữa phát hiện rằng con người là mắt xích yếu nhất. Báo cáo của McAfee chỉ ra rằng có nhiều tổ chức phát triển và triển khai chương trình nâng cao nhận thức cho người dùng trong các lĩnh vực kinh doanh của họ, nhưng hiệu quả của các chương trình này rất khác nhau, và trong một số trường hợp được xác định, ngay cả sau khi đào tạo bảo mật đã được thực hiện, nó gần như không giúp người dùng cuối có được nhận thức bảo mật có giá trị để giảm thiểu mối đe dọa từ tấn công kỹ thuật xã hội.</p><h2 id="cac-loai-phishing" tabindex="-1">Các loại Phishing <a class="header-anchor" href="#cac-loai-phishing" aria-label="Permalink to &quot;Các loại Phishing&quot;">​</a></h2><h3 id="vishing" tabindex="-1">Vishing <a class="header-anchor" href="#vishing" aria-label="Permalink to &quot;Vishing&quot;">​</a></h3><p>Vishing là hình thức phishing thực hiện qua cuộc gọi điện thoại. Vì giọng nói (voice) được sử dụng cho loại phishing này, nó được gọi là vishing → voice + phishing = vishing.</p><p>Xét đến sự dễ dàng và lượng dữ liệu khổng lồ có sẵn trên mạng xã hội, không có gì ngạc nhiên khi những kẻ lừa đảo giao tiếp tự tin qua điện thoại dưới danh nghĩa bạn bè, người thân hoặc bất kỳ thương hiệu liên quan nào, mà không gây ra nghi ngờ.</p><h3 id="smishing" tabindex="-1">Smishing <a class="header-anchor" href="#smishing" aria-label="Permalink to &quot;Smishing&quot;">​</a></h3><p>SMS phishing hay SMiShing là một trong những loại tấn công phishing dễ thực hiện nhất.</p><p>Người dùng bị nhắm mục tiêu thông qua các cảnh báo SMS.</p><p>Trong SMiShing, người dùng có thể nhận được tin nhắn DM giả mạo hoặc chi tiết đơn hàng giả với liên kết hủy đơn.</p><p>Liên kết thực tế sẽ là một trang giả mạo được thiết kế để thu thập thông tin cá nhân.</p><h3 id="search-engine-phishing" tabindex="-1">Search Engine Phishing <a class="header-anchor" href="#search-engine-phishing" aria-label="Permalink to &quot;Search Engine Phishing&quot;">​</a></h3><p>Search engine phishing là loại phishing liên quan đến việc tạo một trang web giả mạo để nhắm mục tiêu vào các từ khóa cụ thể và chờ người tìm kiếm truy cập vào trang web giả đó.</p><p>Khi người tìm kiếm nhấp vào liên kết trang, họ sẽ không bao giờ nhận ra mình đã bị lừa cho đến khi quá muộn.</p><h3 id="spear-phishing" tabindex="-1">Spear Phishing <a class="header-anchor" href="#spear-phishing" aria-label="Permalink to &quot;Spear Phishing&quot;">​</a></h3><p>Không giống như phishing truyền thống – liên quan đến việc gửi email đến hàng triệu người dùng không xác định – spear phishing thường có tính chất nhắm mục tiêu, và các email được thiết kế cẩn thận để nhắm vào một người dùng cụ thể.</p><p>Những cuộc tấn công này có nguy cơ cao hơn vì kẻ lừa đảo thực hiện nghiên cứu hồ sơ xã hội đầy đủ về người dùng và tổ chức của họ – thông qua hồ sơ mạng xã hội và trang web công ty.</p><p>Trong số các loại tấn công phishing khác nhau, Spear phishing là loại tấn công phishing được sử dụng phổ biến nhất – đối với cả người dùng cá nhân lẫn tổ chức.</p><h3 id="whaling" tabindex="-1">Whaling <a class="header-anchor" href="#whaling" aria-label="Permalink to &quot;Whaling&quot;">​</a></h3><p>Whaling không khác nhiều so với spear phishing, nhưng nhóm mục tiêu trở nên cụ thể và giới hạn hơn trong loại tấn công phishing này.</p><p>Kỹ thuật này nhắm vào các vị trí cấp C-suite như CEO, CFO, COO – hoặc bất kỳ vị trí quản lý cấp cao nào khác – những người được coi là những nhân vật lớn trong chuỗi thông tin của bất kỳ tổ chức nào, thường được gọi là &quot;cá voi&quot; trong thuật ngữ phishing.</p><p>Công nghệ, ngân hàng và chăm sóc sức khỏe là các lĩnh vực bị nhắm mục tiêu nhiều nhất cho các cuộc tấn công phishing. Điều này là do hai yếu tố chính: số lượng người dùng lớn và sự phụ thuộc cao vào dữ liệu.</p><p>Liên kết:</p><p><a href="https://youtu.be/D5kg3jZ0Kcw" target="_blank" rel="noreferrer">https://youtu.be/D5kg3jZ0Kcw</a></p><p><a href="https://www.webroot.com/us/en/resources/tips-articles/what-is-social-engineering" target="_blank" rel="noreferrer">https://www.webroot.com/us/en/resources/tips-articles/what-is-social-engineering</a></p><p><a href="https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539" target="_blank" rel="noreferrer">https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539</a></p><p><a href="https://www.csoonline.com/article/2124681/what-is-social-engineering.html" target="_blank" rel="noreferrer">https://www.csoonline.com/article/2124681/what-is-social-engineering.html</a></p><p><a href="https://blog.syscloud.com/types-of-phishing/" target="_blank" rel="noreferrer">https://blog.syscloud.com/types-of-phishing/</a></p>',29)]))}const u=i(a,[["render",g]]);export{m as __pageData,u as default};
